import { Anchor, Code, List, Text, Title } from '@mantine/core';
import type { MDXComponents } from 'mdx/types';

export function useMDXComponents(components: MDXComponents): MDXComponents {
    return {
        h1: ({ children }) => <Title order={1} mb="md">{children}</Title>,
        h2: ({ children }) => <Title order={2} mt="xl" mb="sm">{children}</Title>,
        h3: ({ children }) => <Title order={3} mt="lg" mb="xs">{children}</Title>,
        p: ({ children }) => <Text mb="sm">{children}</Text>,
        a: ({ href, children }) => <Anchor href={href}>{children}</Anchor>,
        ul: ({ children }) => <List mb="sm">{children}</List>,
        ol: ({ children }) => <List type="ordered" mb="sm">{children}</List>,
        li: ({ children }) => <List.Item>{children}</List.Item>,
        code: ({ children }) => <Code>{children}</Code>,
        ...components,
    };
}

